param([string]$BaseUrl='http://localhost:18081',[string]$BackendUrl='http://localhost:18080',[Parameter(Mandatory)][string]$OutputDirectory,[switch]$ApplicationStartedByGenerator)
Set-StrictMode -Version Latest;$ErrorActionPreference='Stop';$repo=[IO.Path]::GetFullPath((Join-Path $PSScriptRoot '..\..'));$m=Get-Content (Join-Path $repo 'docs\manual-usuarios\manifest.json') -Raw|ConvertFrom-Json;$css=Get-Content (Join-Path $repo 'docs\manual-usuarios\templates\manual.css') -Raw;$body='';foreach($i in $m.items){$content=Get-Content (Join-Path $repo ('docs\manual-usuarios\'+$i.content)) -Raw;$shot=Join-Path $OutputDirectory ('screenshots\'+$i.screenshot);$img='';if(Test-Path $shot){$b=[Convert]::ToBase64String([IO.File]::ReadAllBytes($shot));$img="<img class='screen' src='data:image/png;base64,$b'>"};$body+="<section><h2>$($i.title)</h2>$img$content</section>"};$html="<!doctype html><html lang='es'><meta charset='utf-8'><style>$css</style><body><header><h1>Manual visual de Gestudio</h1><p>Capturas obtenidas de la demo local de Gestudio. Las opciones visibles dependen del rol y los permisos.</p></header>$body</body></html>";$hp=Join-Path $OutputDirectory 'manual.html';$html|Set-Content $hp -Encoding utf8;$pdf=Join-Path $OutputDirectory 'Manual_Gestudio_Usuarios_Nuevos.pdf';$js=Join-Path $env:TEMP ('gestudio-render-'+[guid]::NewGuid()+'.mjs');"import{chromium}from'playwright';const b=await chromium.launch(),p=await b.newPage();await p.goto('file:///'+process.env.HTML.replace(/\\\\/g,'/'));await p.pdf({path:process.env.PDF,format:'A4',printBackground:true,displayHeaderFooter:true,headerTemplate:'<span></span>',footerTemplate:'<div style=\"font-size:8px;width:100%;text-align:center\"><span class=\"pageNumber\"></span></div>',margin:{top:'12mm',bottom:'14mm',left:'12mm',right:'12mm'}});await b.close();"|Set-Content $js -Encoding utf8;try{$env:HTML=$hp;$env:PDF=$pdf;Push-Location (Join-Path $repo 'frontend');try{npx --yes -p playwright@1.54.1 node $js;if($LASTEXITCODE-ne 0){throw 'Falló la generación del PDF.'}}finally{Pop-Location}}finally{Remove-Item $js -Force -ErrorAction SilentlyContinue};$meta=[ordered]@{generatedAtUtc=[DateTime]::UtcNow.ToString('o');sourceCommit=(git -C $repo rev-parse HEAD);sourceBranch=(git -C $repo branch --show-current);baseUrl=$BaseUrl;backendUrl=$BackendUrl;viewport='1440x1000';locale='es-AR';timezone='America/Argentina/Buenos_Aires';roles=@('SECRETARIA','CAJA','ADMINISTRADOR','SUPERADMIN');screenshotCount=@(Get-ChildItem (Join-Path $OutputDirectory 'screenshots') -Filter *.png).Count;pageCount=$null;powershellVersion=$PSVersionTable.PSVersion.ToString();nodeVersion=(node --version);npmVersion=(npm --version);playwrightVersion='1.54.1';applicationStartedByGenerator=[bool]$ApplicationStartedByGenerator;pdfFileName='Manual_Gestudio_Usuarios_Nuevos.pdf'};$meta|ConvertTo-Json -Depth 5|Set-Content (Join-Path $OutputDirectory 'metadata.json') -Encoding utf8